import React from 'react';
import './UserProfileCard.css';

interface UserProfileCardProps {
  /** URL for the user's avatar image */
  avatarUrl: string;
  /** User's full name */
  name: string;
  /** User's bio/description */
  bio: string;
  /** Optional: User's job title or role */
  role?: string;
  /** Optional: User's location */
  location?: string;
  /** Optional: Additional CSS class for custom styling */
  className?: string;
  /** Optional: Click handler for the entire card */
  onClick?: () => void;
}

/**
 * A reusable user profile card component displaying avatar, name, and bio
 */
const UserProfileCard: React.FC<UserProfileCardProps> = ({
  avatarUrl,
  name,
  bio,
  role,
  location,
  className = '',
  onClick,
}) => {
  return (
    <div 
      className={`user-profile-card ${className} ${onClick ? 'clickable' : ''}`}
      onClick={onClick}
      role={onClick ? 'button' : 'article'}
      tabIndex={onClick ? 0 : undefined}
    >
      <div className="user-profile-card__avatar-container">
        <img 
          src={avatarUrl} 
          alt={`${name}'s avatar`}
          className="user-profile-card__avatar"
          onError={(e) => {
            // Fallback if image fails to load
            e.currentTarget.src = 'https://via.placeholder.com/100/cccccc/666666?text=User';
          }}
        />
      </div>

      <div className="user-profile-card__content">
        <h3 className="user-profile-card__name">{name}</h3>

        {role && (
          <p className="user-profile-card__role">{role}</p>
        )}

        <p className="user-profile-card__bio">{bio}</p>

        {location && (
          <div className="user-profile-card__location">
            <span className="user-profile-card__location-icon">📍</span>
            <span>{location}</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default UserProfileCard;
```

