```javascript
// error-handler.js
class AppError extends Error {
    constructor(message, statusCode, errorCode) {
        super(message);
        this.statusCode = statusCode;
        this.errorCode = errorCode;
        this.isOperational = true;
        Error.captureStackTrace(this, this.constructor);
    }
}

class ValidationError extends AppError {
    constructor(message, errors) {
        super(message, 400, 'VALIDATION_ERROR');
        this.errors = errors;
    }
}

class OutOfStockError extends AppError {
    constructor(message, unavailableItems) {
        super(message, 409, 'OUT_OF_STOCK');
        this.unavailableItems = unavailableItems;
    }
}

class DatabaseError extends AppError {
    constructor(message) {
        super(message, 503, 'DATABASE_ERROR');
    }
}

const errorHandler = (err, req, res, next) => {
    // Log error for debugging
    console.error('Error:', {
        message: err.message,
        stack: err.stack,
        path: req.path,
        method: req.method,
        timestamp: new Date().toISOString()
    });

    // Default error response
    const statusCode = err.statusCode || 500;
    const response = {
        success: false,
        error: {
            code: err.errorCode || 'INTERNAL_ERROR',
            message: err.message || 'An unexpected error occurred'
        }
    };

    // Add additional details for specific error types
    if (err instanceof ValidationError && err.errors) {
        response.error.details = err.errors;
    }

    if (err instanceof OutOfStockError && err.unavailableItems) {
        response.error.unavailableItems = err.unavailableItems;
    }

    // Don't expose internal errors in production
    if (process.env.NODE_ENV === 'production' && !err.isOperational) {
        response.error.message = 'An internal server error occurred';
    }

    res.status(statusCode).json(response);
};

module.exports = {
    AppError,
    ValidationError,
    OutOfStockError,
    DatabaseError,
    errorHandler
};
```

