class OrderService {
    constructor(dbConnection) {
        this.db = dbConnection;
    }

    async createOrder(orderData) {
        const session = await this.db.startSession();
        session.startTransaction();

        try {
            // Create order document
            const order = {
                ...orderData,
                orderNumber: this.generateOrderNumber(),
                status: 'pending',
                createdAt: new Date(),
                updatedAt: new Date()
            };

            // Save to database
            const result = await this.db.collection('orders').insertOne(order, { session });

            // Update inventory
            await this.updateInventory(orderData.items, session);

            // Commit transaction
            await session.commitTransaction();

            return {
                ...order,
                _id: result.insertedId
            };

        } catch (error) {
            // Rollback transaction on error
            await session.abortTransaction();

            // Handle specific database errors
            if (error.name === 'MongoError' || error.name === 'MongoServerError') {
                if (error.code === 11000) {
                    throw new DatabaseError('Duplicate order detected');
                }
                throw new DatabaseError('Database operation failed');
            }

            // Re-throw other errors
            throw error;

        } finally {
            session.endSession();
        }
    }

    async updateInventory(items, session) {
        for (const item of items) {
            await this.db.collection('inventory').updateOne(
                { productId: item.productId },
                { $inc: { stock: -item.quantity } },
                { session }
            );
        }
    }

    generateOrderNumber() {
        return `ORD-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
    }
}

module.exports = OrderService;
