// server.js
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const { v4: uuidv4 } = require('uuid');

const app = express();
const PORT = process.env.PORT || 3000;

// 1. CORS - handle preflight before anything else
app.use(cors({
  origin: process.env.CORS_ORIGIN || 'http://localhost:3000',
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
  credentials: true,
  maxAge: 86400 // 24 hours
}));

// 2. Request ID - generate correlation ID
app.use((req, res, next) => {
  const requestId = req.headers['x-request-id'] || uuidv4();
  req.requestId = requestId;
  res.setHeader('X-Request-ID', requestId);
  next();
});

// 3. Request logging - log method, path, start time
app.use((req, res, next) => {
  const startTime = Date.now();
  req.startTime = startTime;

  console.log(`[${new Date().toISOString()}] [${req.requestId}] ${req.method} ${req.path} - Started`);

  // Log when response is complete
  res.on('finish', () => {
    const duration = Date.now() - startTime;
    const logLevel = res.statusCode >= 400 ? 'ERROR' : 'INFO';
    console.log(`[${new Date().toISOString()}] [${req.requestId}] ${req.method} ${req.path} ${res.statusCode} - ${duration}ms [${logLevel}]`);
  });

  next();
});

// Security middleware (can go early in the stack)
app.use(helmet());

// 4. Rate limiting - reject before expensive work
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: {
    error: 'Too many requests from this IP, please try again later.',
    requestId: null // Will be populated in middleware
  },
  standardHeaders: true,
  legacyHeaders: false,
  keyGenerator: (req) => req.ip,
  handler: (req, res, next, options) => {
    const message = {
      ...options.message,
      requestId: req.requestId
    };
    res.status(options.statusCode).json(message);
  }
});

app.use('/api/', limiter);

// Body parsing middleware
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// 5. Authentication - verify identity
const authenticate = (req, res, next) => {
  // Extract token from Authorization header
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({
      error: 'Authentication required',
      requestId: req.requestId
    });
  }

  const token = authHeader.split(' ')[1];

  try {
    // In a real app, you would verify the JWT or session token here
    // For example: const decoded = jwt.verify(token, process.env.JWT_SECRET);
    // req.user = decoded;

    // Mock authentication for demonstration
    if (token === 'valid-token') {
      req.user = { id: 'user-123', role: 'user' };
      console.log(`[${req.requestId}] User authenticated: ${req.user.id}`);
      next();
    } else {
      res.status(401).json({
        error: 'Invalid authentication token',
        requestId: req.requestId
      });
    }
  } catch (error) {
    res.status(401).json({
      error: 'Authentication failed',
      requestId: req.requestId
    });
  }
};

// 6. Authorization - verify permissions
const authorize = (requiredRole) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({
        error: 'Authentication required',
        requestId: req.requestId
      });
    }

    // Simple role-based authorization
    const userRole = req.user.role;
    const rolesHierarchy = {
      'admin': 3,
      'moderator': 2,
      'user': 1
    };

    if (rolesHierarchy[userRole] >= rolesHierarchy[requiredRole]) {
      console.log(`[${req.requestId}] User ${req.user.id} authorized as ${userRole}`);
      next();
    } else {
      res.status(403).json({
        error: 'Insufficient permissions',
        requestId: req.requestId,
        requiredRole,
        userRole
      });
    }
  };
};

// 7. Input validation middleware
const validateRequest = (schema) => {
  return (req, res, next) => {
    try {
      // In a real app, use a validation library like Joi or Zod
      // For demonstration, we'll use a simple schema validation
      if (schema.body) {
        for (const [field, validator] of Object.entries(schema.body)) {
          if (validator.required && !req.body[field]) {
            return res.status(400).json({
              error: `Missing required field: ${field}`,
              requestId: req.requestId
            });
          }

          if (req.body[field] && validator.type) {
            const actualType = typeof req.body[field];
            if (actualType !== validator.type) {
              return res.status(400).json({
                error: `Field ${field} must be of type ${validator.type}`,
                requestId: req.requestId
              });
            }
          }
        }
      }

      next();
    } catch (error) {
      res.status(400).json({
        error: 'Validation failed',
        details: error.message,
        requestId: req.requestId
      });
    }
  };
};

// Example validation schema
const userSchema = {
  body: {
    name: { type: 'string', required: true },
    email: { type: 'string', required: true },
    age: { type: 'number', required: false }
  }
};

// 8. Route handlers with middleware chain
app.get('/api/public', (req, res) => {
  res.json({
    message: 'Public endpoint - no authentication required',
    requestId: req.requestId,
    timestamp: new Date().toISOString()
  });
